#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define REC_LENGTH 49

typedef struct latLong {
    float lat;
    float lng;
} LatLong;

typedef struct record {
    char recString[REC_LENGTH];
    float distance;
} Record;

typedef struct {
    LatLong *data;
    int size;
    int capacity;
} LatLongVector;

typedef struct {
    Record *data;
    int size;
    int capacity;
} RecordVector;

void initLatLongVector(LatLongVector *v) {
    v->capacity = 1024;
    v->data = (LatLong *)malloc(sizeof(LatLong) * v->capacity);
    v->size = 0;
}

void pushLatLong(LatLongVector *v, LatLong val) {
    if (v->size >= v->capacity) {
        v->capacity *= 2;
        v->data = (LatLong *)realloc(v->data, sizeof(LatLong) * v->capacity);
    }
    v->data[v->size++] = val;
}

void initRecordVector(RecordVector *v) {
    v->capacity = 1024;
    v->data = (Record *)malloc(sizeof(Record) * v->capacity);
    v->size = 0;
}

void pushRecord(RecordVector *v, Record val) {
    if (v->size >= v->capacity) {
        v->capacity *= 2;
        v->data = (Record *)realloc(v->data, sizeof(Record) * v->capacity);
    }
    v->data[v->size++] = val;
}

void freeLatLongVector(LatLongVector *v) {
    free(v->data);
}

void freeRecordVector(RecordVector *v) {
    free(v->data);
}

void findLowest(RecordVector *records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records->data[i];
        records->data[i] = records->data[minLoc];
        records->data[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records->data[i].distance = distances[i];
    }
}

float *OpenMPFindNearestNeighbors(
    int numRecords,
    LatLongVector *locations,
    float lat,
    float lng,
    int timing) {

    float *d_distances = (float *)malloc(sizeof(float) * numRecords);
    if (!d_distances) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(-1);
    }

    double kernel_start = 0.0, kernel_end = 0.0;

    if (timing) {
        kernel_start = omp_get_wtime();
    }

    #pragma omp parallel for
    for (int v_3 = 0; v_3 < numRecords; v_3++) {
        LatLong *latLong = &locations->data[v_3];
        float diff_lat = lat - latLong->lat;
        float diff_lng = lng - latLong->lng;
        d_distances[v_3] = (float)sqrt((diff_lat * diff_lat) + (diff_lng * diff_lng));
    }

    if (timing) {
        kernel_end = omp_get_wtime();
        printf("# Records\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
        printf("%d        \t%f [%.2fMB]\t%f\t%f [%.2fMB]\t%f\n\n",
               numRecords,
               0.0, (float)((sizeof(LatLong) * numRecords)/1e6),
               kernel_end - kernel_start,
               0.0, (float)((sizeof(float) * numRecords)/1e6),
               kernel_end - kernel_start);
    }

    return d_distances;
}

int loadData(char *filename, RecordVector *records, LatLongVector *locations) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;
    char *data_folder = getenv("DATA_FOLDER");
    if (!data_folder) data_folder = ".";

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "Error opening filelist: %s\n", filename);
        exit(0);
    }

    while (!feof(flist)) {
        if (fscanf(flist, "%s\n", dbname) != 1) {
            if (!feof(flist)) fprintf(stderr, "error reading filelist\n");
            break;
        }
        sprintf(db_fullname, "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while (!feof(fp)) {
            Record record;
            LatLong latLong;
            if (fgets(record.recString, 49, fp) == NULL) break;
            if (feof(fp)) break;

            char substr[6];
            for (i = 0; 5 > i; i++) substr[i] = *(record.recString + i + 28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for (i = 0; 5 > i; i++) substr[i] = *(record.recString + i + 33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            pushLatLong(locations, latLong);
            pushRecord(records, record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

int parseCommandline(int argc, char *argv[], char *filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (2 > argc) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    for (i = 1; argc > i; i++) {
        if ('-' == argv[i][0]) {
            flag = argv[i][1];
            switch (flag) {
            case 'r':
                i++;
                if (i < argc) *r = atoi(argv[i]);
                break;
            case 'l':
                if (strlen(argv[i]) > 2 && 'a' == argv[i][2]) {
                    i++;
                    if (i < argc) *lat = atof(argv[i]);
                } else {
                    i++;
                    if (i < argc) *lng = atof(argv[i]);
                }
                break;
            case 'h':
                return 1;
            case 'q':
                *q = 1;
                break;
            case 't':
                *t = 1;
                break;
            case 'p':
                i++;
                if (i < argc) *p = atoi(argv[i]);
                break;
            case 'd':
                i++;
                if (i < argc) *d = atoi(argv[i]);
                break;
            case 'f':
                i++;
                if (i < argc) {
                    char *data_folder = argv[i];
                    setenv("DATA_FOLDER", data_folder, 1);
                }
                break;
            }
        }
    }
    if ((0 <= *d && 0 > *p) || (0 <= *p && 0 > *d))
        return 1;
    return 0;
}

void printUsage() {
    printf("Nearest Neighbor Usage\n");
    printf("\n");
    printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
    printf("\n");
    printf("filename     the filename that lists the data input files\n");
    printf("-r [int]     the number of records to return (default: 10)\n");
    printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
    printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
    printf("\n");
    printf("-h, --help   Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}

int main(int argc, char *argv[]) {
    RecordVector records;
    LatLongVector locations;
    float *recordDistances;
    int i;

    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;

    initRecordVector(&records);
    initLatLongVector(&locations);

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    int numRecords = loadData(filename, &records, &locations);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (numRecords < resultsCount) resultsCount = numRecords;

    recordDistances = OpenMPFindNearestNeighbors(numRecords, &locations, lat, lng, timing);

    findLowest(&records, recordDistances, numRecords, resultsCount);

    if (!quiet)
        for (i = 0; resultsCount > i; i++) {
            printf("%s --> Distance=%f\n", records.data[i].recString, records.data[i].distance);
        }

    free(recordDistances);
    freeRecordVector(&records);
    freeLatLongVector(&locations);
    return 0;
}
